import{_ as a,o as n,c as e,a2 as t}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"DeerFlow Context Management","description":"","frontmatter":{"title":"DeerFlow Context Management","status":"complete"},"headers":[],"relativePath":"research/agents/deer-flow/context-management.md","filePath":"research/agents/deer-flow/context-management.md"}'),o={name:"research/agents/deer-flow/context-management.md"};function l(p,s,r,i,c,d){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="deerflow-context-management" tabindex="-1">DeerFlow Context Management <a class="header-anchor" href="#deerflow-context-management" aria-label="Permalink to &quot;DeerFlow Context Management&quot;">​</a></h1><h2 id="the-challenge" tabindex="-1">The Challenge <a class="header-anchor" href="#the-challenge" aria-label="Permalink to &quot;The Challenge&quot;">​</a></h2><p>DeerFlow handles long-horizon, multi-step tasks that can span dozens of tool calls, multiple web pages fetched, files written and read, and parallel sub-agent results merged. Without aggressive context management, the LLM&#39;s context window fills quickly.</p><p>DeerFlow addresses this with four complementary strategies:</p><ol><li><strong>Sub-agent context isolation</strong> — parallel work happens in separate context windows</li><li><strong>Progressive skill loading</strong> — only load skill specs when the task needs them</li><li><strong>In-session summarization</strong> — compress completed sub-tasks before they consume too much space</li><li><strong>Filesystem offload</strong> — write intermediate results to disk rather than keeping them in context</li></ol><hr><h2 id="strategy-1-sub-agent-context-isolation" tabindex="-1">Strategy 1: Sub-Agent Context Isolation <a class="header-anchor" href="#strategy-1-sub-agent-context-isolation" aria-label="Permalink to &quot;Strategy 1: Sub-Agent Context Isolation&quot;">​</a></h2><p>The most powerful context management technique in ultra mode is simply not putting everything in one context window.</p><p>Each sub-agent runs in its own <strong>isolated subgraph</strong> with a fresh context:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Lead Agent context window:</span></span>
<span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│  System prompt                          │</span></span>
<span class="line"><span>│  User task                              │</span></span>
<span class="line"><span>│  Plan (step names only, ~500 tokens)   │</span></span>
<span class="line"><span>│  Sub-Agent 1 result (summary)          │ ← ~200 tokens</span></span>
<span class="line"><span>│  Sub-Agent 2 result (summary)          │ ← ~200 tokens</span></span>
<span class="line"><span>│  Sub-Agent N result (summary)          │ ← ~200 tokens</span></span>
<span class="line"><span>│  Reporter synthesis                     │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sub-Agent 1 context (separate):</span></span>
<span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│  System prompt                          │</span></span>
<span class="line"><span>│  Sub-task: &quot;Research market size of X&quot; │</span></span>
<span class="line"><span>│  Tool calls + results (web searches)   │ ← potentially large</span></span>
<span class="line"><span>│  Intermediate findings                  │</span></span>
<span class="line"><span>│  Final SubAgentResult                  │</span></span>
<span class="line"><span>└────────────────────────────────────────┘  (discarded after completion)</span></span></code></pre></div><p><strong>Key invariant</strong>: Only the <code>SubAgentResult</code> (a compact structured summary) crosses the sub-agent boundary. The raw tool calls, intermediate web page content, and reasoning steps are discarded when the sub-agent completes.</p><p>This mirrors the pattern documented in <a href="./../../concepts/multi-agent-systems/real-world-examples.html">ForgeCode&#39;s bounded context model</a> and <a href="./../../concepts/context-management/multi-agent-context.html">Claude Code&#39;s sub-agent isolation</a>, but DeerFlow applies it to dynamically spawned sub-agents rather than statically defined ones.</p><hr><h2 id="strategy-2-progressive-skill-loading" tabindex="-1">Strategy 2: Progressive Skill Loading <a class="header-anchor" href="#strategy-2-progressive-skill-loading" aria-label="Permalink to &quot;Strategy 2: Progressive Skill Loading&quot;">​</a></h2><p>Skills (Markdown workflow specifications) are loaded <strong>only when the current task needs them</strong>. At the start of a session, no skill files are in context.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Session start → context: [system_prompt, user_message]</span></span>
<span class="line"><span>                                          ↓</span></span>
<span class="line"><span>Task: &quot;Write a research report on X&quot;</span></span>
<span class="line"><span>                                          ↓</span></span>
<span class="line"><span>Classifier detects intent → loads skills:</span></span>
<span class="line"><span>  context: [system_prompt, user_message,</span></span>
<span class="line"><span>            research/SKILL.md (~2K tokens),</span></span>
<span class="line"><span>            report-generation/SKILL.md (~2K tokens)]</span></span>
<span class="line"><span>                                          ↓</span></span>
<span class="line"><span>Task: &quot;Create slides from the report&quot;</span></span>
<span class="line"><span>                                          ↓</span></span>
<span class="line"><span>New intent detected → loads slide skill:</span></span>
<span class="line"><span>  context: [..., slide-creation/SKILL.md (~2K tokens)]</span></span></code></pre></div><p><strong>Contrast with always-loading all skills:</strong></p><ul><li>5 built-in skills × ~2K tokens each = ~10K tokens always consumed</li><li>Progressive loading: 0 tokens at start, load only what&#39;s needed</li></ul><p>For models with smaller context windows (32K–64K), this savings is significant.</p><hr><h2 id="strategy-3-in-session-summarization" tabindex="-1">Strategy 3: In-Session Summarization <a class="header-anchor" href="#strategy-3-in-session-summarization" aria-label="Permalink to &quot;Strategy 3: In-Session Summarization&quot;">​</a></h2><p>Within a long researcher loop, DeerFlow monitors context usage and summarizes completed sub-tasks before they crowd out future work:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Simplified representation</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> researcher</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    while</span><span style="color:#CBA6F7;"> not</span><span style="color:#89B4FA;"> task_complete</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">        response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">invoke_with_tools</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> tools</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">        state </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> append_tool_results</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> response</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Context pressure check</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#89B4FA;"> context_usage</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &gt;</span><span style="color:#CDD6F4;"> SUMMARIZATION_THRESHOLD</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            # Identify completed sub-tasks in message history</span></span>
<span class="line"><span style="color:#CDD6F4;">            completed </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> find_completed_subtasks</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            # Compress them: replace raw tool calls + results with a summary</span></span>
<span class="line"><span style="color:#CDD6F4;">            summary </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">summarize</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">completed</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">            state </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> replace_with_summary</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> completed</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> summary</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>The summarization threshold is set conservatively enough to ensure there&#39;s always room for the current tool call and its response.</p><hr><h2 id="strategy-4-filesystem-offload" tabindex="-1">Strategy 4: Filesystem Offload <a class="header-anchor" href="#strategy-4-filesystem-offload" aria-label="Permalink to &quot;Strategy 4: Filesystem Offload&quot;">​</a></h2><p>Rather than accumulating all intermediate results in the context window, DeerFlow encourages (via skill instructions and tool behavior) writing results to the sandbox filesystem:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Instead of:</span></span>
<span class="line"><span>  context: [search result 1 (2000 tokens), search result 2 (1800 tokens),</span></span>
<span class="line"><span>            fetched page 1 (5000 tokens), fetched page 2 (4200 tokens), ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DeerFlow does:</span></span>
<span class="line"><span>  write: /mnt/user-data/workspace/research-notes.md ← (stored on disk)</span></span>
<span class="line"><span>  write: /mnt/user-data/workspace/source-1.md</span></span>
<span class="line"><span>  write: /mnt/user-data/workspace/source-2.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  context: [&quot;Saved 4 sources to workspace. Reading now as needed.&quot;]</span></span></code></pre></div><p>The agent can then <code>file_read</code> specific sections on demand rather than keeping all content in the active context window simultaneously.</p><p>This is especially effective for research tasks where raw web content can easily exceed 50K tokens across multiple pages.</p><hr><h2 id="memory-cross-session-persistence" tabindex="-1">Memory: Cross-Session Persistence <a class="header-anchor" href="#memory-cross-session-persistence" aria-label="Permalink to &quot;Memory: Cross-Session Persistence&quot;">​</a></h2><p>Beyond within-session context management, DeerFlow maintains <strong>long-term memory</strong> across sessions:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Session N ends → memory update:</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;user_profile&quot;: {</span></span>
<span class="line"><span>    &quot;name&quot;: &quot;...&quot;,</span></span>
<span class="line"><span>    &quot;technical_stack&quot;: [&quot;Python&quot;, &quot;FastAPI&quot;, &quot;PostgreSQL&quot;],</span></span>
<span class="line"><span>    &quot;writing_style&quot;: &quot;concise, bullet-point heavy&quot;,</span></span>
<span class="line"><span>    &quot;preferred_output&quot;: &quot;markdown reports&quot;,</span></span>
<span class="line"><span>    &quot;recurring_workflows&quot;: [&quot;competitor analysis&quot;, &quot;market research&quot;]</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;accumulated_knowledge&quot;: {</span></span>
<span class="line"><span>    &quot;domain_context&quot;: [...],</span></span>
<span class="line"><span>    &quot;past_research_summaries&quot;: [...]</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session N+1 starts → memory injected into system prompt:</span></span>
<span class="line"><span>  &quot;Based on past interactions, this user prefers Python stack,</span></span>
<span class="line"><span>   concise markdown reports, and works frequently on market research.&quot;</span></span></code></pre></div><p>Memory is stored <strong>locally</strong> and remains under user control. It is not sent to any cloud service by default.</p><p>This is architecturally similar to <a href="./../../../concepts/context-management/memory-systems.html#mem0">Mem0&#39;s approach</a> — automatic extraction of useful facts from conversations — but implemented as part of the harness itself rather than a separate service.</p><hr><h2 id="comparison-with-other-agents" tabindex="-1">Comparison with Other Agents <a class="header-anchor" href="#comparison-with-other-agents" aria-label="Permalink to &quot;Comparison with Other Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Technique</th><th>DeerFlow</th><th>Claude Code</th><th>ForgeCode</th><th>Goose</th></tr></thead><tbody><tr><td>Sub-agent context isolation</td><td>✓ (all sub-agents)</td><td>✓ (task tool)</td><td>✓ (bounded context)</td><td>✓ (summon)</td></tr><tr><td>Progressive skill/tool loading</td><td>✓ (on-demand)</td><td>—</td><td>—</td><td>Partial</td></tr><tr><td>In-session summarization</td><td>✓</td><td>✓ (auto-compact)</td><td>✓</td><td>✓ (tool-pair)</td></tr><tr><td>Filesystem offload</td><td>✓ (sandbox FS)</td><td>✓ (workspace)</td><td>—</td><td>—</td></tr><tr><td>Cross-session memory</td><td>✓ (built-in)</td><td>✓ (CLAUDE.md)</td><td>—</td><td>Partial</td></tr><tr><td>Token counting pre-send</td><td>Implicit (LangGraph)</td><td>✓ (explicit)</td><td>✓ (token budget)</td><td>✓</td></tr></tbody></table>`,39)])])}const h=a(o,[["render",l]]);export{m as __pageData,h as default};
